                            {item.isVegetarian && <Badge variant="secondary">Vegetarian</Badge>}
                            {item.isGlutenFree && <Badge variant="secondary">GF</Badge>}
                            {item.isSpicy && <Badge variant="secondary">Spicy</Badge>}
