    description: "Fresh Atlantic salmon with lemon butter sauce and seasonal vegetables",
    price: "22.99",
    imageUrl: "/menu/salmon.png",
    category: "Mains",
    isVegan: false,
    isGlutenFree: true,
    isSpicy: false,
    allergens: ["Fish", "Dairy"],
    modifiers: [],
  },
  {
    name: "Chocolate Lava Cake",
    description: "Warm chocolate cake with molten center, served with vanilla ice cream",
    price: "8.99",
    imageUrl: "/menu/cake.png",
    category: "Desserts",
    isVegan: false,
    isGlutenFree: false,
    isSpicy: false,
    allergens: ["Gluten", "Dairy", "Eggs"],
    modifiers: [],
  },
  {
    name: "Margherita Pizza",
    description: "Classic pizza with fresh mozzarella, tomato sauce, and basil",
    price: "15.99",
    imageUrl: "/menu/pizza.png",
    category: "Mains",
    isVegan: false,
    isGlutenFree: false,
    isSpicy: false,
    allergens: ["Gluten", "Dairy"],
    modifiers: [
      { name: "Extra Mozzarella", additionalCost: "2.00" },
      { name: "Add Olives", additionalCost: "1.00" },
    ],
  },
];

export async function seedDatabase() {
  console.log("Seeding database...");

  // Check if menu items already exist
  const existingItems = await db.select().from(menuItems);
  if (existingItems.length > 0) {
    console.log("Database already seeded, skipping...");
    return;
  }

  // Seed categories
  const categoryMap: Record<string, number> = {};
  for (const cat of categoryData) {
    const [created] = await db.insert(categories).values(cat).returning();
    categoryMap[cat.name] = created.id;
  }

  // Seed menu items
  for (const item of menuData) {
    const { modifiers: itemModifiers, category, ...menuItem } = item;
    const [created] = await db.insert(menuItems).values({
      ...menuItem,
      categoryId: categoryMap[category],
    }).returning();

    // Add modifiers
    for (const mod of itemModifiers) {
      await db.insert(modifiers).values({
        menuItemId: created.id,
        name: mod.name,
        additionalCost: mod.additionalCost,
      });
    }
  }

  // Seed tables (1-12)
  for (let i = 1; i <= 12; i++) {
    await db.insert(restaurantTables).values({ tableNumber: i });
  }

  // Seed staff users
  const staffData = [
    { username: "kitchen1", password: "kitchen123", name: "Kitchen Staff", role: "kitchen" as const },
    { username: "waiter1", password: "waiter123", name: "Waiter Staff", role: "waiter" as const },
    { username: "owner1", password: "owner123", name: "Restaurant Owner", role: "owner" as const },
  ];

  let ownerId: number | null = null;
  for (const staffUser of staffData) {
    const passwordHash = await bcrypt.hash(staffUser.password, 10);
    const [created] = await db.insert(staff).values({
      username: staffUser.username,
      passwordHash,
      name: staffUser.name,
      role: staffUser.role,
    }).returning();

    if (staffUser.role === "owner") {
      ownerId = created.id;
    }
  }

  // Seed default restaurant for owner
  if (ownerId) {
    await db.insert(restaurants).values({
      name: "MyDine Restaurant",
      address: "123 Main Street, Foodville, CA 90210",
      phone: "(555) 123-4567",
      email: "info@mydine.com",
      description: "A wonderful dining experience with great food and service",
      ownerId: ownerId,
      isActive: true,
    });
  }

  console.log("Database seeded successfully!");
}

